import { useState } from 'react';
import {
  SquarePen, Trash2, PanelLeftClose, PanelLeft,
  MessageSquare, Search, Settings, Clock, LogOut,
} from 'lucide-react';
import { Dot } from './ds';

const ICON_SIZE = 18;
const ICON_STROKE = 1.8;

function SidebarIcon({ Icon, label, onClick, active, collapsed }) {
  const [hover, setHover] = useState(false);
  return (
    <button
      onClick={onClick}
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => setHover(false)}
      title={label}
      style={{
        display: 'flex', alignItems: 'center', gap: 10,
        padding: collapsed ? '10px 0' : '10px 12px',
        justifyContent: collapsed ? 'center' : 'flex-start',
        width: '100%',
        background: active ? 'var(--sidebar-active)' : hover ? 'var(--sidebar-hover)' : 'transparent',
        border: 'none', borderRadius: 8, cursor: 'pointer',
        color: active ? 'var(--sidebar-text)' : 'var(--sidebar-text-muted)',
        fontSize: 13, fontWeight: 500,
        fontFamily: 'var(--f-ui)',
        transition: 'background 0.15s, color 0.15s',
        outline: 'none',
      }}
    >
      <Icon size={ICON_SIZE} strokeWidth={ICON_STROKE} style={{ flexShrink: 0 }} />
      {!collapsed && <span>{label}</span>}
    </button>
  );
}

export default function ChatSidebar({
  conversations, activeId, onSelect, onNewChat, onDelete,
  collapsed, onToggle, health, onSearch, onSettings,
}) {
  const [hoverId, setHoverId] = useState(null);
  const [showHistory, setShowHistory] = useState(true);

  const width = collapsed ? 60 : 260;

  return (
    <div style={{
      width, minWidth: width,
      background: 'var(--sidebar-bg)',
      display: 'flex', flexDirection: 'column',
      transition: 'width 0.25s cubic-bezier(0.4, 0, 0.2, 1), min-width 0.25s cubic-bezier(0.4, 0, 0.2, 1)',
      borderRight: '1px solid var(--sidebar-border)',
      overflow: 'hidden',
    }}>

      {/* Toggle button */}
      <div style={{
        padding: collapsed ? '12px 0' : '12px 12px',
        display: 'flex', alignItems: 'center',
        justifyContent: collapsed ? 'center' : 'space-between',
        flexShrink: 0,
      }}>
        <button
          onClick={onToggle}
          style={{
            background: 'none', border: 'none', cursor: 'pointer',
            color: 'var(--sidebar-text-muted)', padding: 6, borderRadius: 6,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            transition: 'color 0.15s',
          }}
          title={collapsed ? 'Expand sidebar' : 'Collapse sidebar'}
        >
          {collapsed
            ? <PanelLeft size={ICON_SIZE} strokeWidth={ICON_STROKE} />
            : <PanelLeftClose size={ICON_SIZE} strokeWidth={ICON_STROKE} />}
        </button>
        {!collapsed && (
          <span style={{
            fontSize: 14, fontWeight: 600, color: 'var(--sidebar-text)',
            letterSpacing: '-0.01em',
          }}>
            Stock AI
          </span>
        )}
      </div>

      {/* Navigation icons */}
      <div style={{
        padding: collapsed ? '4px 10px' : '4px 8px',
        display: 'flex', flexDirection: 'column', gap: 2,
        flexShrink: 0,
      }}>
        <SidebarIcon Icon={SquarePen} label="New Chat" onClick={onNewChat} collapsed={collapsed} />
        <SidebarIcon Icon={Search} label="Search" onClick={onSearch} collapsed={collapsed} />
        <SidebarIcon Icon={Clock} label="History" onClick={() => setShowHistory(p => !p)} active={showHistory && !collapsed} collapsed={collapsed} />
        <SidebarIcon Icon={Settings} label="Settings" onClick={onSettings} collapsed={collapsed} />
      </div>

      {/* Divider */}
      <div style={{
        height: 1, background: 'var(--sidebar-border)',
        margin: collapsed ? '8px 10px' : '8px 12px',
        flexShrink: 0,
      }} />

      {/* Conversation list — only when expanded */}
      {!collapsed && (
        <div style={{ flex: 1, overflowY: 'auto', padding: '4px 8px' }}>
          {conversations.length === 0 ? (
            <p style={{
              color: 'var(--sidebar-text-muted)', fontSize: 12,
              textAlign: 'center', padding: '24px 12px', lineHeight: 1.6,
            }}>
              No conversations yet
            </p>
          ) : (
            conversations.map(conv => {
              const isActive = conv.id === activeId;
              const isHover = conv.id === hoverId;
              return (
                <div
                  key={conv.id}
                  onClick={() => onSelect(conv.id)}
                  onMouseEnter={() => setHoverId(conv.id)}
                  onMouseLeave={() => setHoverId(null)}
                  style={{
                    padding: '9px 10px',
                    borderRadius: 8,
                    cursor: 'pointer',
                    background: isActive ? 'var(--sidebar-active)' : isHover ? 'var(--sidebar-hover)' : 'transparent',
                    display: 'flex', alignItems: 'center', gap: 8,
                    marginBottom: 2,
                    transition: 'background 0.12s',
                  }}
                >
                  <MessageSquare size={14} strokeWidth={1.5} color="var(--sidebar-text-muted)" style={{ flexShrink: 0 }} />
                  <span style={{
                    flex: 1, fontSize: 13, color: 'var(--sidebar-text)',
                    overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                  }}>
                    {conv.title}
                  </span>
                  {(isHover || isActive) && (
                    <button
                      onClick={(e) => { e.stopPropagation(); onDelete(conv.id); }}
                      style={{
                        background: 'none', border: 'none', cursor: 'pointer',
                        color: 'var(--sidebar-text-muted)', padding: 2,
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        flexShrink: 0, borderRadius: 4, opacity: 0.7,
                      }}
                      title="Delete conversation"
                    >
                      <Trash2 size={14} strokeWidth={1.8} />
                    </button>
                  )}
                </div>
              );
            })
          )}
        </div>
      )}

      {/* Spacer when collapsed */}
      {collapsed && <div style={{ flex: 1 }} />}

      {/* Bottom section */}
      <div style={{
        borderTop: '1px solid var(--sidebar-border)',
        padding: collapsed ? '8px 10px' : '8px',
        flexShrink: 0,
        display: 'flex', flexDirection: 'column', gap: 2,
      }}>
        {/* Status */}
        {!collapsed && (
          <div style={{
            padding: '6px 12px', fontSize: 11,
            color: 'var(--sidebar-text-muted)',
            display: 'flex', alignItems: 'center', gap: 6,
          }}>
            <Dot on={health?.anthropic && health?.openai} />
            {health?.anthropic && health?.openai ? 'All systems online' : 'Setup needed'}
          </div>
        )}

        {/* Logout */}
        <SidebarIcon Icon={LogOut} label="Logout" onClick={() => {
          localStorage.removeItem('stockai-conversations');
          localStorage.removeItem('stockai-active');
          window.location.reload();
        }} collapsed={collapsed} />
      </div>
    </div>
  );
}
